class LoginController extends GetxController {
  // Reactive form fields
  var email = ''.obs;
  var password = ''.obs;

  // Reactive error messages
  var emailError = ''.obs;
  var passwordError = ''.obs;

  void validateEmail(String value) {
    email.value = value;
    if (value.isEmpty) {
      emailError.value = 'Email is required';
    } else if (!value.contains('@')) {
      emailError.value = 'Enter a valid email address';
    } else {
      emailError.value = '';
    }
  }

  void validatePassword(String value) {
    password.value = value;
    if (value.isEmpty) {
      passwordError.value = 'Password is required';
    } else if (value.length < 6) {
      passwordError.value = 'Password must be at least 6 characters';
    } else {
      passwordError.value = '';
    }
  }

  bool get isFormValid => emailError.value.isEmpty && passwordError.value.isEmpty && email.value.isNotEmpty && password.value.isNotEmpty;

  void submit() {
    if (isFormValid) {
      // Perform login
      Get.snackbar('Success', 'Logged in with ${email.value}');
    } else {
      Get.snackbar('Error', 'Please fix validation errors');
    }
  }
}

class LoginPage extends GetView<LoginController> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Login')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          children: [
            TextField(
              decoration: InputDecoration(
                labelText: 'Email',
                errorText: controller.emailError.value.isEmpty ? null : controller.emailError.value,
              ),
              onChanged: controller.validateEmail,
            ),
            SizedBox(height: 16),
            TextField(
              obscureText: true,
              decoration: InputDecoration(
                labelText: 'Password',
                errorText: controller.passwordError.value.isEmpty ? null : controller.passwordError.value,
              ),
              onChanged: controller.validatePassword,
            ),
            SizedBox(height: 20),
            Obx(() => ElevatedButton(
              onPressed: controller.isFormValid ? controller.submit : null,
              child: Text('Login'),
            )),
          ],
        ),
      ),
    );
  }
}

class FormController extends GetxController {
  final formKey = GlobalKey<FormState>();
  var email = ''.obs;
  var password = ''.obs;

  String? validateEmail(String? value) {
    if (value == null || value.isEmpty) return 'Email is required';
    if (!value.contains('@')) return 'Invalid email';
    email.value = value;
    return null;
  }

  String? validatePassword(String? value) {
    if (value == null || value.isEmpty) return 'Password is required';
    if (value.length < 6) return 'Minimum 6 characters';
    password.value = value;
    return null;
  }

  void submit() {
    if (formKey.currentState!.validate()) {
      // Form is valid, proceed
      Get.snackbar('Success', 'Welcome ${email.value}');
    }
  }
}

class FormPage extends GetView<FormController> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Form with GlobalKey')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Form(
          key: controller.formKey,
          child: Column(
            children: [
              TextFormField(
                decoration: InputDecoration(labelText: 'Email'),
                validator: controller.validateEmail,
              ),
              TextFormField(
                decoration: InputDecoration(labelText: 'Password'),
                obscureText: true,
                validator: controller.validatePassword,
              ),
              SizedBox(height: 20),
              ElevatedButton(
                onPressed: controller.submit,
                child: Text('Submit'),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

